mapper.select:
SELECT

FROM MESSENGER_CONTENT mc

WHERE mc.MSGR_ID = #{msgrId}
  AND COALESCE(mc.DEL_YN, 'N') = 'N'
ORDER BY mc.SEND_DT DESC, mc.MSG_CONT_ID DESC
LIMIT #{limit}

SELECT

FROM MESSENGER_CONTENT mc

WHERE mc.MSGR_ID = #{msgrId}
  AND COALESCE(mc.DEL_YN, 'N') = 'N'
  AND (
        mc.SEND_DT < #{beforeSendDt}

            OR (mc.SEND_DT = #{beforeSendDt} AND mc.MSG_CONT_ID < #{beforeMsgContId})

      )
ORDER BY mc.SEND_DT DESC, mc.MSG_CONT_ID DESC
LIMIT #{limit}

mapper.update:
UPDATE MESSENGER_CONTENT
SET READ_YN = 'Y'
WHERE MSG_CONT_ID = #{msgContId}

UPDATE MESSENGER_CONTENT
SET DEL_YN = 'Y'
WHERE MSG_CONT_ID = #{msgContId}
  AND (
        USER_ID = #{userId}
        OR EXISTS (
            SELECT 1
            FROM MESSENGER_USER mu
            WHERE mu.MSGR_ID = MESSENGER_CONTENT.MSGR_ID
              AND mu.USER_ID = #{userId}
              AND mu.ROLE_CD = 'owner'
              AND mu.LEFT_DT IS NULL
        )
      )
